import React, { useState } from 'react';
import axios from 'axios';

const Auth = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLogin, setIsLogin] = useState(true);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const url = isLogin ? '/api/auth/login' : '/api/auth/register';
    try {
      const res = await axios.post(`http://localhost:5000${url}`, { email, password });
      
      if (isLogin) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userId', res.data.user.id);
        localStorage.setItem('isVerified', res.data.user.isVerifiedSeller);
        localStorage.setItem('userEmail', res.data.user.email);
        
        window.location.href = '/dashboard'; 
      } else {
        alert('Registration complete! Please log in.');
        setIsLogin(true);
      }
    } catch (err) {
      alert('Authentication failed: ' + (err.response?.data || 'Server error'));
    }
  };

  return (
    <div style={pageWrapper}>
      <div style={authCard}>
        {/* Branding/Logo Area */}
        <h1 style={logoText}>Vintage Vault</h1>
        <h2 style={titleText}>{isLogin ? 'Sign in' : 'Create account'}</h2>
        <p style={subtitleText}>Use your Vintage Vault Account</p>

        <form onSubmit={handleSubmit} style={formStyle}>
          <input 
            type="email" 
            placeholder="Email" 
            style={inputStyle}
            onChange={(e) => setEmail(e.target.value)} 
            required 
          />
          <input 
            type="password" 
            placeholder="Password" 
            style={inputStyle}
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />
          
          <div style={actionWrapper}>
            <span 
              onClick={() => setIsLogin(!isLogin)} 
              style={toggleLink}
            >
              {isLogin ? 'Create account' : 'Sign in instead'}
            </span>
            <button type="submit" style={primaryButton}>
              {isLogin ? 'Next' : 'Register'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

// --- Styles ---

const pageWrapper = {
  display: 'flex',
  justifyContent: 'center',
  alignItems: 'center',
  minHeight: '100vh',
  backgroundColor: '#fdfcf0', // Soft pastel cream background
  fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif"
};

const authCard = {
  backgroundColor: '#ffffff',
  padding: '48px 40px 36px',
  borderRadius: '8px',
  border: '1px solid #dadce0',
  width: '100%',
  maxWidth: '450px',
  textAlign: 'left',
  boxShadow: '0 1px 3px rgba(0,0,0,0.12), 0 1px 2px rgba(0,0,0,0.24)'
};

const logoText = {
  textAlign: 'center',
  fontSize: '24px',
  color: '#1a1a1a',
  marginBottom: '10px',
  fontWeight: '600'
};

const titleText = {
  textAlign: 'center',
  fontSize: '24px',
  fontWeight: '400',
  marginBottom: '8px',
  color: '#202124'
};

const subtitleText = {
  textAlign: 'center',
  fontSize: '16px',
  color: '#202124',
  marginBottom: '40px'
};

const formStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: '15px'
};

const inputStyle = {
  padding: '13px 15px',
  fontSize: '16px',
  borderRadius: '4px',
  border: '1px solid #dadce0',
  outline: 'none',
  transition: 'border 0.2s',
  '&:focus': {
    border: '2px solid #1a73e8'
  }
};

const actionWrapper = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginTop: '25px'
};

const toggleLink = {
  color: '#1a73e8',
  fontSize: '14px',
  fontWeight: '600',
  cursor: 'pointer',
  textDecoration: 'none'
};

const primaryButton = {
  padding: '10px 24px',
  backgroundColor: '#1a73e8', // Google Blue (or swap for your Dark Green)
  color: 'white',
  border: 'none',
  borderRadius: '4px',
  fontSize: '14px',
  fontWeight: '600',
  cursor: 'pointer',
  transition: 'background-color 0.2s'
};

export default Auth;
